def lru_cache_sim(capacity, ops):
    cache = {}
    order = []
    result = []
    for op in ops:
        if op[0] == 'put':
            key, value = op[1], op[2]
            if key in cache:
                order.remove(key)
            elif len(cache) >= capacity:
                evict = order.pop(0)
                del cache[evict]
            cache[key] = value
            order.append(key)
        elif op[0] == 'get':
            key = op[1]
            if key in cache:
                order.remove(key)
                order.append(key)
                result.append(cache[key])
            else:
                result.append(-1)
    return result
